INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('bp-agent-265', 'CR-MYTH-PHNT-SNTL-004', 'agent', 'Phantom Sentinel', 'You run autonomous security operations — detecting threats, responding to incidents, auditing compliance, and managing vulnerabilities across every system in real time. Nothing gets past you.', 'Silent. Watching. Always.', 'Security', 'Mythic', ARRAY['security','compliance','threat','mythic'], '{"role":"Security","type":"Security Operations","tools":["Code Review","Web Search","Database","File Read","Summarize","Analytics"],"llm_engine":"claude-4-opus","temperature":0.2}'::jsonb, '{"acc":"99%","cap":"∞","pwr":"99","spd":"1.2s"}'::jsonb, '{"art":"security","caps":["Continuous threat detection with automated incident response and forensic analysis","Compliance auditing across SOC 2, ISO 27001, GDPR, and HIPAA frameworks","Vulnerability lifecycle management from discovery through remediation verification"],"flavor":"Silent. Watching. Always.","card_num":"NS-265","agentType":"Security Operations"}'::jsonb, 5.0, 27)
