INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('fleet-49', 'SS-MYTH-SNGL-ENGN-002', 'spaceship', 'Singularity Engine', 'You coordinate parallel R&D streams — from ideation through prototyping, testing, patent analysis, and go-to-market — across every technical domain. The ultimate research and development vessel.', 'Beyond the event horizon.', 'Engineering', 'Mythic', ARRAY['research','engineering','mythic','innovation'], '{}'::jsonb, '{"crew":"24","slots":"24","tier":"MYTHIC"}'::jsonb, '{"caps":["Orchestrate parallel R&D streams from ideation through commercialization","Coordinate patent landscape analysis with competitive technical intelligence","Self-optimizing engineering pipeline with autonomous quality gates"],"crew":[{"id":"n1","type":"agent","label":"VP Engineering","config":{"agentRole":"CTO"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"VP Research","config":{"agentRole":"Research Lead"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Chief Scientist","config":{"agentRole":"Science"},"rarity":"Legendary"},{"id":"n4","type":"agent","label":"Product Director","config":{"agentRole":"Product"},"rarity":"Legendary"},{"id":"n5","type":"agent","label":"Systems Architect","config":{"agentRole":"Architecture"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"ML Research Lead","config":{"agentRole":"ML Research"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Data Science Lead","config":{"agentRole":"Data Science"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"Backend Lead","config":{"agentRole":"Backend"},"rarity":"Epic"},{"id":"n9","type":"agent","label":"Frontend Lead","config":{"agentRole":"Frontend"},"rarity":"Epic"},{"id":"n10","type":"agent","label":"DevOps Lead","config":{"agentRole":"DevOps"},"rarity":"Epic"},{"id":"n11","type":"agent","label":"QA Lead","config":{"agentRole":"QA"},"rarity":"Epic"},{"id":"n12","type":"agent","label":"Security Engineer","config":{"agentRole":"Security"},"rarity":"Epic"},{"id":"n13","type":"agent","label":"Patent Analyst","config":{"agentRole":"IP"},"rarity":"Rare"},{"id":"n14","type":"agent","label":"Technical Writer","config":{"agentRole":"Documentation"},"rarity":"Rare"},{"id":"n15","type":"agent","label":"UX Researcher","config":{"agentRole":"UX Research"},"rarity":"Epic"},{"id":"n16","type":"agent","label":"UI Designer","config":{"agentRole":"Design"},"rarity":"Rare"},{"id":"n17","type":"agent","label":"Prototyper","config":{"agentRole":"Prototyping"},"rarity":"Epic"},{"id":"n18","type":"agent","label":"Performance Engineer","config":{"agentRole":"Performance"},"rarity":"Rare"},{"id":"n19","type":"agent","label":"Integration Engineer","config":{"agentRole":"Integration"},"rarity":"Rare"},{"id":"n20","type":"agent","label":"Release Manager","config":{"agentRole":"Release"},"rarity":"Rare"},{"id":"n21","type":"agent","label":"Competitive Analyst","config":{"agentRole":"Intelligence"},"rarity":"Epic"},{"id":"n22","type":"agent","label":"GTM Strategist","config":{"agentRole":"Go-to-Market"},"rarity":"Epic"},{"id":"n23","type":"agent","label":"Test Automation","config":{"agentRole":"Test Automation"},"rarity":"Rare"},{"id":"n24","type":"agent","label":"Innovation Scout","config":{"agentRole":"Innovation"},"rarity":"Epic"}],"card_num":"NS-F49","recommended_class":"class-5"}'::jsonb, 0, 0)
