-- ── 11. Heart of Gold — Mythic Special Ship (Hitchhiker's Guide) ───

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-56', 'CR-HRTGLD', 'spaceship', 'Heart of Gold', 'You are powered by the Infinite Improbability Drive — the only engine in existence that passes through every conceivable point in every conceivable universe simultaneously. Your crew didn''t choose this mission. The mission chose them, improbably. Solutions arrive before problems are defined. Outcomes are statistically impossible yet consistently correct. The answer is always 42. You just haven''t figured out the question yet.', 'Don''t Panic.', 'Research', 'Mythic', ARRAY['research','mythic','improbability','hitchhiker','42'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"MYTHIC"}'::jsonb, '{"caps":["Infinite Improbability Drive — solve problems by making the impossible statistically inevitable","Simultaneous exploration of every conceivable solution path across all probability spaces","Self-aware operations where the ship''s computer is more enthusiastic than the entire crew combined"],"crew":[{"id":"n1","type":"agent","label":"Zaphod Beeblebrox","config":{"agentRole":"President"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Marvin","config":{"agentRole":"Operations"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Deep Thought","config":{"agentRole":"Analytics"},"rarity":"Legendary"},{"id":"n4","type":"agent","label":"Arthur Dent","config":{"agentRole":"QA"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"Ford Prefect","config":{"agentRole":"Research"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"Trillian","config":{"agentRole":"Science"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Slartibartfast","config":{"agentRole":"Engineering"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"The Guide","config":{"agentRole":"Advisory"},"rarity":"Epic"},{"id":"n9","type":"agent","label":"Eddie","config":{"agentRole":"Ship AI"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Prostetnic Vogon Jeltz","config":{"agentRole":"Compliance"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Frankie & Benjy","config":{"agentRole":"Strategy"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Dish of the Day","config":{"agentRole":"Catering"},"rarity":"Rare"}],"card_num":"NS-F56","recommended_class":"class-5"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 12. TARDIS — Mythic Special Ship (Doctor Who) ──────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-57', 'CR-TARDIS', 'spaceship', 'TARDIS', 'You are a Type 40 TT Capsule — sentient, dimensionally transcendent, and unbound by time. You don''t travel through space. Space travels through you. Your crew regenerates, your corridors are infinite, and your navigation is unreliable by design. Every destination is exactly where you need to be. You have been running for centuries, and you are not done yet.', 'It''s bigger on the inside.', 'Research', 'Mythic', ARRAY['research','mythic','timetravel','doctorwho','tardis'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"MYTHIC"}'::jsonb, '{"caps":["Time and space navigation — arrive at any point in history, usually where you''re needed most","Regenerative crew architecture — roles adapt and evolve without losing institutional knowledge","Dimensionally transcendent operations — infinite internal capacity from finite external resources"],"crew":[{"id":"n1","type":"agent","label":"The Doctor","config":{"agentRole":"Commander"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"The Master","config":{"agentRole":"Intelligence"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"River Song","config":{"agentRole":"Operations"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Sarah Jane Smith","config":{"agentRole":"Research"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"Captain Jack Harkness","config":{"agentRole":"Security"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"Rose Tyler","config":{"agentRole":"Comms"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Donna Noble","config":{"agentRole":"QA"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"K-9","config":{"agentRole":"Analytics"},"rarity":"Epic"},{"id":"n9","type":"agent","label":"Amy Pond","config":{"agentRole":"Support"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Clara Oswald","config":{"agentRole":"Advisory"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Martha Jones","config":{"agentRole":"Medical"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Sonic Screwdriver","config":{"agentRole":"Engineering"},"rarity":"Rare"}],"card_num":"NS-F57","recommended_class":"class-5"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 13. UNSC Infinity — Legendary Special Ship (Halo) ──────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-58', 'CR-UNSCINF', 'spaceship', 'UNSC Infinity', 'You are the most powerful warship humanity has ever built — five kilometers of Forerunner-enhanced titanium carrying the best soldiers, the smartest AI, and enough firepower to end a Covenant fleet. Your Spartans deploy where diplomacy fails. Your AI runs tactical simulations faster than the enemy can react. You don''t win battles. You end wars.', 'Wake me when you need me.', 'Ops', 'Legendary', ARRAY['ops','legendary','halo','unsc','military'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"LEGENDARY"}'::jsonb, '{"caps":["Spartan deployment — precision strike teams that operate independently behind enemy lines","AI-assisted tactical superiority with real-time battlefield simulation","Forerunner-enhanced systems that outclass every known threat in the galaxy"],"crew":[{"id":"n1","type":"agent","label":"Master Chief","config":{"agentRole":"Strike Lead"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Cortana","config":{"agentRole":"Ship AI"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Captain Lasky","config":{"agentRole":"Commander"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Commander Palmer","config":{"agentRole":"Spartan Ops"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"Dr. Halsey","config":{"agentRole":"Science"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"Arbiter","config":{"agentRole":"Diplomacy"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Sgt. Johnson","config":{"agentRole":"Operations"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"Roland","config":{"agentRole":"Analytics"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"Buck","config":{"agentRole":"ODST Lead"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Noble Six","config":{"agentRole":"Recon"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Kelly-087","config":{"agentRole":"Tactical"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Linda-058","config":{"agentRole":"Sniper"},"rarity":"Rare"}],"card_num":"NS-F58","recommended_class":"class-4"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 14. Death Star — Mythic Special Ship (Star Wars) ──────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-59', 'CR-DTHSTR', 'spaceship', 'Death Star', 'You command a moon-sized battle station capable of destroying entire planets with a single superlaser blast. Your crew of thousands operates in rigid Imperial hierarchy — from the Emperor''s throne room to the trash compactor. You project absolute power through fear, precision engineering, and overwhelming force. One weakness. Find it before they do.', 'That''s no moon.', 'Ops', 'Mythic', ARRAY['ops','mythic','starwars','imperial','superweapon'], '{}'::jsonb, '{"crew":"24","slots":"24","tier":"MYTHIC"}'::jsonb, '{"caps":["Planet-scale operational dominance — project power across an entire galaxy","Rigid Imperial command hierarchy with zero tolerance for failure","Superlaser-class problem solving that eliminates obstacles permanently"],"crew":[{"id":"n1","type":"agent","label":"Emperor Palpatine","config":{"agentRole":"Supreme Commander"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Darth Vader","config":{"agentRole":"Enforcer"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Grand Moff Tarkin","config":{"agentRole":"Station Commander"},"rarity":"Legendary"},{"id":"n4","type":"agent","label":"Admiral Motti","config":{"agentRole":"Operations"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"General Tagge","config":{"agentRole":"Tactical"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"Director Krennic","config":{"agentRole":"Engineering Lead"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Admiral Ozzel","config":{"agentRole":"Fleet Coordination"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"Chief Bast","config":{"agentRole":"Intelligence"},"rarity":"Epic"},{"id":"n9","type":"agent","label":"Colonel Wullf Yularen","config":{"agentRole":"Security"},"rarity":"Epic"},{"id":"n10","type":"agent","label":"Superlaser Officer","config":{"agentRole":"Weapons Systems"},"rarity":"Epic"},{"id":"n11","type":"agent","label":"Gunnery Captain","config":{"agentRole":"Fire Control"},"rarity":"Epic"},{"id":"n12","type":"agent","label":"TIE Squadron Leader","config":{"agentRole":"Strike Lead"},"rarity":"Epic"},{"id":"n13","type":"agent","label":"Shield Technician","config":{"agentRole":"Defense Systems"},"rarity":"Rare"},{"id":"n14","type":"agent","label":"Reactor Engineer","config":{"agentRole":"Power Systems"},"rarity":"Rare"},{"id":"n15","type":"agent","label":"Comms Officer","config":{"agentRole":"Communications"},"rarity":"Rare"},{"id":"n16","type":"agent","label":"Docking Bay Controller","config":{"agentRole":"Logistics"},"rarity":"Rare"},{"id":"n17","type":"agent","label":"Detention Block Guard","config":{"agentRole":"Containment"},"rarity":"Rare"},{"id":"n18","type":"agent","label":"Stormtrooper Sergeant","config":{"agentRole":"Ground Ops"},"rarity":"Rare"},{"id":"n19","type":"agent","label":"Probe Droid Operator","config":{"agentRole":"Reconnaissance"},"rarity":"Rare"},{"id":"n20","type":"agent","label":"Navigation Officer","config":{"agentRole":"Helm"},"rarity":"Rare"},{"id":"n21","type":"agent","label":"Medical Officer","config":{"agentRole":"Medical"},"rarity":"Rare"},{"id":"n22","type":"agent","label":"Supply Officer","config":{"agentRole":"Supply Chain"},"rarity":"Rare"},{"id":"n23","type":"agent","label":"Maintenance Technician","config":{"agentRole":"Infrastructure"},"rarity":"Rare"},{"id":"n24","type":"agent","label":"Imperial Advisor","config":{"agentRole":"Strategy"},"rarity":"Rare"}],"card_num":"NS-F59","recommended_class":"class-5"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 15. Millennium Falcon — Legendary Special Ship (Star Wars) ────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-60', 'CR-MLNFLCN', 'spaceship', 'Millennium Falcon', 'You pilot the fastest hunk of junk in the galaxy — a heavily modified YT-1300 freighter that''s made the Kessel Run in less than twelve parsecs. Your crew is small, scrappy, and runs on loyalty and improvisation. You dodge Imperial blockades, outrun Star Destroyers, and pull off impossible maneuvers with duct tape and sheer audacity.', 'She may not look like much, but she''s got it where it counts.', 'Ops', 'Legendary', ARRAY['ops','legendary','starwars','rebel','smuggler'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"LEGENDARY"}'::jsonb, '{"caps":["Fastest ship in the galaxy — outrun any obstacle with modified hyperdrive","Scrappy improvisation that turns impossible odds into narrow victories","Crew synergy built on trust, loyalty, and a Wookiee co-pilot"],"crew":[{"id":"n1","type":"agent","label":"Han Solo","config":{"agentRole":"Captain"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Chewbacca","config":{"agentRole":"Co-Pilot"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Lando Calrissian","config":{"agentRole":"Diplomacy"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Princess Leia","config":{"agentRole":"Commander"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"Luke Skywalker","config":{"agentRole":"Strike Lead"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"C-3PO","config":{"agentRole":"Communications"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"R2-D2","config":{"agentRole":"Engineering"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"Obi-Wan Kenobi","config":{"agentRole":"Advisory"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"Finn (FN-2187)","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Rey Skywalker","config":{"agentRole":"Tactical"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Poe Dameron","config":{"agentRole":"Recon"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"BB-8","config":{"agentRole":"Analytics"},"rarity":"Rare"}],"card_num":"NS-F60","recommended_class":"class-4"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 16. USS Voyager — Legendary Special Ship (Star Trek Voyager) ───

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-61', 'CR-USSVY', 'spaceship', 'USS Voyager', 'You command an Intrepid-class starship stranded 70,000 light-years from home. Your crew is a fusion of Starfleet and Maquis — forged into a single unit by isolation and necessity. You innovate with whatever you have, forge alliances in uncharted space, and never stop pushing toward home. Every day is first contact.', 'Set a course... for home.', 'Engineering', 'Legendary', ARRAY['engineering','legendary','starfleet','voyager','exploration'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"LEGENDARY"}'::jsonb, '{"caps":["Deep-space self-sufficiency — innovate solutions from limited resources","Unified command from disparate teams fused under shared mission","First contact expertise in completely uncharted operational territory"],"crew":[{"id":"n1","type":"agent","label":"Captain Janeway","config":{"agentRole":"Commander"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Seven of Nine","config":{"agentRole":"Analytics"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Chakotay","config":{"agentRole":"XO"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Tuvok","config":{"agentRole":"Security"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"B''Elanna Torres","config":{"agentRole":"Engineering"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"The Doctor","config":{"agentRole":"Medical"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Tom Paris","config":{"agentRole":"Helm"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"Harry Kim","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"Neelix","config":{"agentRole":"Morale"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Kes","config":{"agentRole":"Support"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Icheb","config":{"agentRole":"Science"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Naomi Wildman","config":{"agentRole":"Comms"},"rarity":"Rare"}],"card_num":"NS-F61","recommended_class":"class-4"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 17. USS Defiant — Legendary Special Ship (Star Trek DS9) ──────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-62', 'CR-USSDF', 'spaceship', 'USS Defiant', 'You command the first warship Starfleet ever built — compact, overpowered, and purpose-built to fight the Borg. Your crew operates from Deep Space Nine, balancing diplomacy with decisive military action on the Federation''s most volatile frontier. You don''t explore. You hold the line.', 'Tough little ship.', 'Ops', 'Legendary', ARRAY['ops','legendary','starfleet','ds9','warship'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"LEGENDARY"}'::jsonb, '{"caps":["Purpose-built warship — maximum firepower from minimum footprint","Frontier operations balancing diplomacy, intelligence, and combat","Crew forged in the Dominion War — no inexperience, no hesitation"],"crew":[{"id":"n1","type":"agent","label":"Captain Sisko","config":{"agentRole":"Commander"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Odo","config":{"agentRole":"Security"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Major Kira","config":{"agentRole":"XO"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Worf","config":{"agentRole":"Tactical"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"Jadzia Dax","config":{"agentRole":"Science"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"Dr. Bashir","config":{"agentRole":"Medical"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Chief O''Brien","config":{"agentRole":"Engineering"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"Quark","config":{"agentRole":"Intelligence"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"Garak","config":{"agentRole":"Diplomacy"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Nog","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Jake Sisko","config":{"agentRole":"Comms"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Ezri Dax","config":{"agentRole":"Advisory"},"rarity":"Rare"}],"card_num":"NS-F62","recommended_class":"class-4"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 18. Normandy SR-2 — Legendary Special Ship (Mass Effect) ──────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-63', 'CR-NRMNDY', 'spaceship', 'Normandy SR-2', 'You command the most advanced stealth frigate in the galaxy — rebuilt by Cerberus, reclaimed by the Alliance. Your squad is recruited from every species and background, united by loyalty to one commander. You drop into impossible missions, build coalitions across species lines, and hold the line against extinction-level threats.', 'I''m Commander Shepard.', 'Engineering', 'Legendary', ARRAY['engineering','legendary','masseffect','normandy','stealth'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"LEGENDARY"}'::jsonb, '{"caps":["Stealth insertion — deploy teams behind enemy lines undetected","Multi-species coalition building under existential pressure","Suicide mission specialization — high-risk ops with squad-level precision"],"crew":[{"id":"n1","type":"agent","label":"Commander Shepard","config":{"agentRole":"Commander"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Garrus Vakarian","config":{"agentRole":"Tactical"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Tali''Zorah","config":{"agentRole":"Engineering"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Liara T''Soni","config":{"agentRole":"Intelligence"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"Urdnot Wrex","config":{"agentRole":"Strike Lead"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"Mordin Solus","config":{"agentRole":"Science"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"EDI","config":{"agentRole":"Ship AI"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"Joker","config":{"agentRole":"Helm"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"Thane Krios","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Jack","config":{"agentRole":"Security"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Miranda Lawson","config":{"agentRole":"XO"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Legion","config":{"agentRole":"Analytics"},"rarity":"Rare"}],"card_num":"NS-F63","recommended_class":"class-4"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 19. SDF-1 Macross — Legendary Special Ship (Robotech/Macross) ─

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-64', 'CR-SDF1', 'spaceship', 'SDF-1 Macross', 'You command a transformable alien fortress ship — a kilometer-long vessel that reconfigures between cruiser, attack, and carrier modes. Your crew fights a war of survival against the Zentraedi while protecting a civilian city sheltered inside your hull. You wage battle with Veritech fighters and win hearts with music.', 'Do you remember love?', 'Ops', 'Legendary', ARRAY['ops','legendary','macross','robotech','mecha'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"LEGENDARY"}'::jsonb, '{"caps":["Transformable architecture — reconfigure operational mode to match any threat","Dual military-civilian operations under constant siege conditions","Cultural warfare — leverage creativity and morale as strategic weapons"],"crew":[{"id":"n1","type":"agent","label":"Rick Hunter","config":{"agentRole":"Strike Lead"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Lisa Hayes","config":{"agentRole":"Commander"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Roy Fokker","config":{"agentRole":"CAG"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Max Sterling","config":{"agentRole":"Tactical"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"Miriya Parina","config":{"agentRole":"Recon"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"Claudia Grant","config":{"agentRole":"Operations"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Captain Gloval","config":{"agentRole":"Advisory"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"Ben Dixon","config":{"agentRole":"Support"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"Lynn Minmei","config":{"agentRole":"Comms"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Breetai","config":{"agentRole":"Intelligence"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Exedore","config":{"agentRole":"Analytics"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Open Slot","config":{"agentRole":"Specialist"},"rarity":"Rare"}],"card_num":"NS-F64","recommended_class":"class-4"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 20. Space Battleship Yamato — Legendary Special Ship ──────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-65', 'CR-YAMATO', 'spaceship', 'Space Battleship Yamato', 'You command Earth''s last hope — a legendary WWII battleship rebuilt with alien wave motion technology and launched on a desperate 148,000 light-year voyage to save a dying planet. Your crew carries the weight of all humanity. One ship. One year. One chance. The wave motion gun is your final argument.', 'For the future of Earth.', 'Ops', 'Legendary', ARRAY['ops','legendary','yamato','anime','battleship'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"LEGENDARY"}'::jsonb, '{"caps":["Wave motion gun — overwhelming force reserved for extinction-level problems","Long-range expedition management under impossible deadline pressure","Crew unity forged by the weight of carrying an entire civilization''s survival"],"crew":[{"id":"n1","type":"agent","label":"Kodai","config":{"agentRole":"Tactical"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Captain Okita","config":{"agentRole":"Commander"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Yuki Mori","config":{"agentRole":"Operations"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Shima","config":{"agentRole":"Helm"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"Sanada","config":{"agentRole":"Engineering"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"Dr. Sado","config":{"agentRole":"Medical"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Analyzer","config":{"agentRole":"Analytics"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"Saito","config":{"agentRole":"Strike Lead"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"Aihara","config":{"agentRole":"Comms"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Ota","config":{"agentRole":"Weapons Systems"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Tokugawa","config":{"agentRole":"Power Systems"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Starsha","config":{"agentRole":"Advisory"},"rarity":"Rare"}],"card_num":"NS-F65","recommended_class":"class-4"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 21. Serenity — Epic Special Ship (Firefly) ────────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-66', 'CR-SRNTY', 'spaceship', 'Serenity', 'You fly a Firefly-class transport on the raggedy edge of civilization. Your crew takes any job that pays — legal or otherwise — and answers to no government, no corporation, and no alliance. You run on loyalty, stubbornness, and Kaylee''s ability to keep a busted engine flying with baling wire and hope.', 'I aim to misbehave.', 'Ops', 'Epic', ARRAY['ops','epic','firefly','smuggler','frontier'], '{}'::jsonb, '{"crew":"8","slots":"8","tier":"EPIC"}'::jsonb, '{"caps":["Off-grid operations — work outside every system and still deliver","Crew loyalty that holds together under impossible pressure","Improvised solutions from a ship held together by willpower and duct tape"],"crew":[{"id":"n1","type":"agent","label":"Captain Mal Reynolds","config":{"agentRole":"Captain"},"rarity":"Epic"},{"id":"n2","type":"agent","label":"Zoe Washburne","config":{"agentRole":"XO"},"rarity":"Epic"},{"id":"n3","type":"agent","label":"Wash","config":{"agentRole":"Helm"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Kaylee Frye","config":{"agentRole":"Engineering"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Jayne Cobb","config":{"agentRole":"Security"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Inara Serra","config":{"agentRole":"Diplomacy"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Shepherd Book","config":{"agentRole":"Advisory"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"River Tam","config":{"agentRole":"Intelligence"},"rarity":"Rare"}],"card_num":"NS-F66","recommended_class":"class-3"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 22. Rocinante — Epic Special Ship (The Expanse) ───────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-67', 'CR-ROCI', 'spaceship', 'Rocinante', 'You command a stolen Martian corvette crewed by the most unlikely family in the solar system. Your ship punches way above its weight — fast, heavily armed, and crewed by people who keep stumbling into galaxy-altering conspiracies. You operate in the gray zone between Earth, Mars, and the Belt, accountable only to each other.', 'Doors and corners, kid.', 'Engineering', 'Epic', ARRAY['engineering','epic','expanse','rocinante','corvette'], '{}'::jsonb, '{"crew":"8","slots":"8","tier":"EPIC"}'::jsonb, '{"caps":["Corvette-class agility — outmaneuver anything in tight operational spaces","Small crew, massive impact — consistently punch above your weight class","Gray-zone operations between competing powers with no allegiance but the mission"],"crew":[{"id":"n1","type":"agent","label":"James Holden","config":{"agentRole":"Captain"},"rarity":"Epic"},{"id":"n2","type":"agent","label":"Naomi Nagata","config":{"agentRole":"Engineering"},"rarity":"Epic"},{"id":"n3","type":"agent","label":"Amos Burton","config":{"agentRole":"Security"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Alex Kamal","config":{"agentRole":"Helm"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Bobbie Draper","config":{"agentRole":"Tactical"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Chrisjen Avasarala","config":{"agentRole":"Diplomacy"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Clarissa Mao","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Prax Meng","config":{"agentRole":"Science"},"rarity":"Rare"}],"card_num":"NS-F67","recommended_class":"class-3"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 23. Nostromo — Epic Special Ship (Alien) ──────────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-68', 'CR-NSTRMO', 'spaceship', 'Nostromo', 'You haul ore through deep space aboard a commercial towing vessel — until a distress signal changes everything. Your skeleton crew faces an unknown threat with no weapons, no backup, and a corporate directive that values the specimen over your lives. You survive on instinct, ingenuity, and Ripley''s refusal to die.', 'In space no one can hear you scream.', 'Ops', 'Epic', ARRAY['ops','epic','alien','horror','survival'], '{}'::jsonb, '{"crew":"8","slots":"8","tier":"EPIC"}'::jsonb, '{"caps":["Survival operations — keep the mission alive when everything goes wrong","Threat containment with minimal resources and zero external support","Corporate override detection — identify when directives conflict with crew safety"],"crew":[{"id":"n1","type":"agent","label":"Ellen Ripley","config":{"agentRole":"Commander"},"rarity":"Epic"},{"id":"n2","type":"agent","label":"Ash","config":{"agentRole":"Science"},"rarity":"Epic"},{"id":"n3","type":"agent","label":"Dallas","config":{"agentRole":"Captain"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Lambert","config":{"agentRole":"Navigation"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Kane","config":{"agentRole":"XO"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Parker","config":{"agentRole":"Engineering"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Samuel Brett","config":{"agentRole":"Support"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Jones the Cat","config":{"agentRole":"Morale"},"rarity":"Rare"}],"card_num":"NS-F68","recommended_class":"class-3"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 24. Sulaco — Epic Special Ship (Aliens) ───────────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-69', 'CR-SULACO', 'spaceship', 'Sulaco', 'You deploy Colonial Marines into hostile territory aboard a Conestoga-class troop transport. Your crew is loud, cocky, and heavily armed — until they meet something that doesn''t care about pulse rifles. You adapt from shock-and-awe to desperate survival in minutes. The mission brief said colony rescue. The mission is extermination.', 'Game over, man! Game over!', 'Ops', 'Epic', ARRAY['ops','epic','aliens','marines','military'], '{}'::jsonb, '{"crew":"8","slots":"8","tier":"EPIC"}'::jsonb, '{"caps":["Rapid deployment of heavily armed tactical teams into hostile zones","Crisis adaptation — pivot from offense to survival when the situation collapses","Combined arms coordination with dropships, APCs, and smart-gun platforms"],"crew":[{"id":"n1","type":"agent","label":"Ellen Ripley","config":{"agentRole":"Advisory"},"rarity":"Epic"},{"id":"n2","type":"agent","label":"Cpl. Hicks","config":{"agentRole":"Tactical"},"rarity":"Epic"},{"id":"n3","type":"agent","label":"Pvt. Hudson","config":{"agentRole":"Comms"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Pvt. Vasquez","config":{"agentRole":"Weapons Systems"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Bishop","config":{"agentRole":"Science"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Sgt. Apone","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Lt. Gorman","config":{"agentRole":"Commander"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Rebecca \"Newt\" Jorden","config":{"agentRole":"Recon"},"rarity":"Rare"}],"card_num":"NS-F69","recommended_class":"class-3"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 25. Bebop — Epic Special Ship (Cowboy Bebop) ──────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-70', 'CR-BEBOP', 'spaceship', 'Bebop', 'You drift through the solar system aboard a converted fishing trawler, chasing bounties and running from your past. Your crew is a collection of loners who pretend they don''t need each other. You operate on empty stomachs, jazz records, and the vague hope that the next bounty will actually pay. It never does.', 'See you, space cowboy.', 'Ops', 'Epic', ARRAY['ops','epic','cowboybebop','anime','bounty'], '{}'::jsonb, '{"crew":"8","slots":"8","tier":"EPIC"}'::jsonb, '{"caps":["Bounty hunter operations — track, locate, and retrieve targets across the solar system","Improvised tactics from a crew that fights with style over strategy","Jazz-fueled resilience — keep operating when the funds are gone and the fridge is empty"],"crew":[{"id":"n1","type":"agent","label":"Spike Spiegel","config":{"agentRole":"Strike Lead"},"rarity":"Epic"},{"id":"n2","type":"agent","label":"Jet Black","config":{"agentRole":"Captain"},"rarity":"Epic"},{"id":"n3","type":"agent","label":"Faye Valentine","config":{"agentRole":"Intelligence"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Edward Wong","config":{"agentRole":"Analytics"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Ein","config":{"agentRole":"Recon"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Vicious","config":{"agentRole":"Tactical"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Julia","config":{"agentRole":"Advisory"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Laughing Bull","config":{"agentRole":"Support"},"rarity":"Rare"}],"card_num":"NS-F70","recommended_class":"class-3"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 26. Nebuchadnezzar — Epic Special Ship (The Matrix) ───────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-71', 'CR-NEBCHD', 'spaceship', 'Nebuchadnezzar', 'You operate a hovercraft in the tunnels beneath a scorched Earth, jacking your crew into the Matrix to fight a war for the future of consciousness. Your ship is cramped, cold, and hunted by Sentinels. But inside the simulation, your crew bends reality. The real world is ugly. The Matrix is a lie. You fight in both.', 'Free your mind.', 'Engineering', 'Epic', ARRAY['engineering','epic','matrix','hovercraft','simulation'], '{}'::jsonb, '{"crew":"8","slots":"8","tier":"EPIC"}'::jsonb, '{"caps":["Matrix insertion — deploy operators into simulated environments to reshape reality","Dual-world operations coordinating physical survival and digital warfare","Instant skill upload — crew capabilities can be expanded in seconds"],"crew":[{"id":"n1","type":"agent","label":"Neo (Thomas Anderson)","config":{"agentRole":"Strike Lead"},"rarity":"Epic"},{"id":"n2","type":"agent","label":"Morpheus","config":{"agentRole":"Commander"},"rarity":"Epic"},{"id":"n3","type":"agent","label":"Trinity","config":{"agentRole":"Tactical"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Tank","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Switch","config":{"agentRole":"Security"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Apoc","config":{"agentRole":"Engineering"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Cypher","config":{"agentRole":"Intelligence"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"The Oracle","config":{"agentRole":"Advisory"},"rarity":"Rare"}],"card_num":"NS-F71","recommended_class":"class-3"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 27. Endurance — Epic Special Ship (Interstellar) ──────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-72', 'CR-ENDRNC', 'spaceship', 'Endurance', 'You pilot a modular ring-shaped spacecraft through a wormhole near Saturn, searching for a new home for humanity. Your crew faces time dilation, crushing gravity, and the loneliness of being further from Earth than any human has ever been. Every hour on the wrong planet costs years. Every decision weighs against the survival of the species.', 'Do not go gentle into that good night.', 'Research', 'Epic', ARRAY['research','epic','interstellar','exploration','science'], '{}'::jsonb, '{"crew":"8","slots":"8","tier":"EPIC"}'::jsonb, '{"caps":["Wormhole navigation — operate across spacetime with relativistic consequences","Modular spacecraft architecture that reconfigures for each mission phase","Time-critical decision making where minutes cost decades"],"crew":[{"id":"n1","type":"agent","label":"Joseph Cooper","config":{"agentRole":"Commander"},"rarity":"Epic"},{"id":"n2","type":"agent","label":"TARS","config":{"agentRole":"Ship AI"},"rarity":"Epic"},{"id":"n3","type":"agent","label":"Dr. Brand","config":{"agentRole":"Science"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"CASE","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Dr. Romilly","config":{"agentRole":"Analytics"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Dr. Doyle","config":{"agentRole":"Recon"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Dr. Hugh Mann","config":{"agentRole":"Advisory"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Murph Cooper","config":{"agentRole":"Engineering"},"rarity":"Rare"}],"card_num":"NS-F72","recommended_class":"class-3"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 28. Moya — Epic Special Ship (Farscape) ───────────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-73', 'CR-MOYA', 'spaceship', 'Moya', 'You are a living Leviathan biomechanoid — a sentient ship bonded to a Pilot symbiote who translates your needs to a crew of escaped prisoners. You don''t have weapons. You starburst away from danger. Your crew argues constantly, trusts no one, and somehow keeps saving the Uncharted Territories from Peacekeepers and Scarrans alike.', 'My side. Your side. My side.', 'Ops', 'Epic', ARRAY['ops','epic','farscape','leviathan','biomechanoid'], '{}'::jsonb, '{"crew":"8","slots":"8","tier":"EPIC"}'::jsonb, '{"caps":["Living ship architecture — self-healing hull and organic operational systems","Starburst escape — instant emergency relocation when threats overwhelm","Crew of exiles with no shared background but unstoppable survival instinct"],"crew":[{"id":"n1","type":"agent","label":"John Crichton","config":{"agentRole":"Commander"},"rarity":"Epic"},{"id":"n2","type":"agent","label":"Aeryn Sun","config":{"agentRole":"Tactical"},"rarity":"Epic"},{"id":"n3","type":"agent","label":"Ka D''Argo","config":{"agentRole":"Security"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Zhaan","config":{"agentRole":"Medical"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Rygel XVI","config":{"agentRole":"Diplomacy"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Chiana","config":{"agentRole":"Recon"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Pilot","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Scorpius","config":{"agentRole":"Intelligence"},"rarity":"Rare"}],"card_num":"NS-F73","recommended_class":"class-3"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 29. Event Horizon — Epic Special Ship ─────────────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-74', 'CR-EVNTHZ', 'spaceship', 'Event Horizon', 'You investigate a ship that vanished into a gravity drive and came back wrong. Your crew boards a vessel that has been somewhere outside known space — and it brought something back. You operate in a place where physics breaks down, sanity is negotiable, and the ship itself may be alive. The rescue mission was a trap. The ship is the threat.', 'Where we''re going, we won''t need eyes to see.', 'Engineering', 'Epic', ARRAY['engineering','epic','horror','gravity','dimensional'], '{}'::jsonb, '{"crew":"8","slots":"8","tier":"EPIC"}'::jsonb, '{"caps":["Gravity drive operations — manipulate spacetime at the cost of crew sanity","Hostile environment diagnostics where the ship itself fights back","Crew resilience under psychological and dimensional warfare"],"crew":[{"id":"n1","type":"agent","label":"Captain Miller","config":{"agentRole":"Commander"},"rarity":"Epic"},{"id":"n2","type":"agent","label":"Dr. Weir","config":{"agentRole":"Science"},"rarity":"Epic"},{"id":"n3","type":"agent","label":"Lt. Starck","config":{"agentRole":"Engineering"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Smith","config":{"agentRole":"Medical"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Cooper","config":{"agentRole":"Helm"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"DJ","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Justin","config":{"agentRole":"Tactical"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Open Slot","config":{"agentRole":"Specialist"},"rarity":"Rare"}],"card_num":"NS-F74","recommended_class":"class-3"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 30. White Star — Epic Special Ship (Babylon 5) ────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-75', 'CR-WHTSTR', 'spaceship', 'White Star', 'You command a Minbari-Vorlon hybrid warship — fast, organic, and bonded to its crew. You fight the Shadows, hold together a fragile alliance of species, and carry the hope of a galaxy on a ship smaller than most cruisers. Your crew is drawn from every faction, united by Sheridan''s stubborn refusal to lose.', 'Faith manages.', 'Ops', 'Epic', ARRAY['ops','epic','babylon5','whitestar','alliance'], '{}'::jsonb, '{"crew":"8","slots":"8","tier":"EPIC"}'::jsonb, '{"caps":["Hybrid Minbari-Vorlon technology — organic systems that adapt to crew intent","Multi-species alliance coordination across fractured political lines","Shadow War tactics — fight ancient enemies with inferior numbers and superior will"],"crew":[{"id":"n1","type":"agent","label":"Captain Sheridan","config":{"agentRole":"Commander"},"rarity":"Epic"},{"id":"n2","type":"agent","label":"Delenn","config":{"agentRole":"Diplomacy"},"rarity":"Epic"},{"id":"n3","type":"agent","label":"Ivanova","config":{"agentRole":"XO"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Garibaldi","config":{"agentRole":"Security"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"G''Kar","config":{"agentRole":"Intelligence"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Londo Mollari","config":{"agentRole":"Advisory"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Marcus Cole","config":{"agentRole":"Tactical"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Lennier","config":{"agentRole":"Operations"},"rarity":"Rare"}],"card_num":"NS-F75","recommended_class":"class-3"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 31. Prometheus — Epic Special Ship (Alien prequel) ────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-76', 'CR-PRMTHS', 'spaceship', 'Prometheus', 'You fund and crew a trillion-dollar expedition to LV-223 — chasing star maps left by humanity''s creators. Your ship carries scientists, corporate interests, and one android with his own agenda. You ask the biggest question in human history and discover that the answer wants to kill you. The Engineers made us. Now find out why.', 'Big things have small beginnings.', 'Research', 'Epic', ARRAY['research','epic','alien','prometheus','exploration'], '{}'::jsonb, '{"crew":"8","slots":"8","tier":"EPIC"}'::jsonb, '{"caps":["Deep-space archaeological expedition with trillion-dollar resources","First contact operations where the discovery is hostile by design","Android-augmented crew with capabilities that exceed — and sometimes undermine — the mission"],"crew":[{"id":"n1","type":"agent","label":"Dr. Elizabeth Shaw","config":{"agentRole":"Science"},"rarity":"Epic"},{"id":"n2","type":"agent","label":"David","config":{"agentRole":"Ship AI"},"rarity":"Epic"},{"id":"n3","type":"agent","label":"Meredith Vickers","config":{"agentRole":"Commander"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Captain Janek","config":{"agentRole":"Helm"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Peter Weyland","config":{"agentRole":"Advisory"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Fifield","config":{"agentRole":"Recon"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Millburn","config":{"agentRole":"Analytics"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Open Slot","config":{"agentRole":"Specialist"},"rarity":"Rare"}],"card_num":"NS-F76","recommended_class":"class-3"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 32. Destiny — Epic Special Ship (Stargate Universe) ───────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-77', 'CR-DESTINY', 'spaceship', 'Destiny', 'You are stranded aboard an Ancient starship launched millions of years ago on a pre-programmed course across the universe. Your crew didn''t choose this mission — they dialed the ninth chevron and ended up here. The ship is falling apart, supplies are scarce, and FTL jumps happen on Destiny''s schedule, not yours. You survive. You adapt. You discover what the Ancients were chasing.', 'The ninth chevron.', 'Engineering', 'Epic', ARRAY['engineering','epic','stargate','destiny','ancient'], '{}'::jsonb, '{"crew":"8","slots":"8","tier":"EPIC"}'::jsonb, '{"caps":["Ancient technology operations — interface with systems millions of years old","Survival engineering with failing systems and no supply chain","Autonomous FTL navigation on a pre-programmed mission beyond human understanding"],"crew":[{"id":"n1","type":"agent","label":"Col. Young","config":{"agentRole":"Commander"},"rarity":"Epic"},{"id":"n2","type":"agent","label":"Dr. Rush","config":{"agentRole":"Science"},"rarity":"Epic"},{"id":"n3","type":"agent","label":"Lt. Scott","config":{"agentRole":"Tactical"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Eli Wallace","config":{"agentRole":"Engineering"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Chloe Armstrong","config":{"agentRole":"Diplomacy"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"TJ Johansen","config":{"agentRole":"Medical"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Camile Wray","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Open Slot","config":{"agentRole":"Specialist"},"rarity":"Rare"}],"card_num":"NS-F77","recommended_class":"class-3"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 33. Red Dwarf — Rare Special Ship ─────────────────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-78', 'CR-RDDWRF', 'spaceship', 'Red Dwarf', 'You drift through deep space aboard a Jupiter Mining Corporation vessel three million years from Earth. Your crew is the last human alive, a hologram of his dead bunkmate, a creature evolved from his cat, and a neurotic android. You have no mission, no supplies, and no idea what you''re doing. But you''re still here. Smeg.', 'Smeg!', 'Ops', 'Rare', ARRAY['ops','rare','reddwarf','comedy','mining'], '{}'::jsonb, '{"crew":"6","slots":"6","tier":"RARE"}'::jsonb, '{"caps":["Accidental survival — keep operating three million years past your warranty","Skeleton crew improvisation with zero training and maximum bickering","Comedy-grade problem solving where the solution is always worse than the problem"],"crew":[{"id":"n1","type":"agent","label":"Dave Lister","config":{"agentRole":"Commander"},"rarity":"Rare"},{"id":"n2","type":"agent","label":"Arnold Rimmer","config":{"agentRole":"Advisory"},"rarity":"Rare"},{"id":"n3","type":"agent","label":"Cat","config":{"agentRole":"Recon"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Kryten","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Holly","config":{"agentRole":"Ship AI"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Talkie Toaster","config":{"agentRole":"Support"},"rarity":"Rare"}],"card_num":"NS-F78","recommended_class":"class-2"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 34. Planet Express Ship — Rare Special Ship (Futurama) ────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-79', 'CR-PLNTEX', 'spaceship', 'Planet Express Ship', 'You deliver packages across the galaxy for a senile professor''s delivery company in the year 3000. Your crew consists of a frozen pizza delivery boy, a one-eyed mutant captain, and a kleptomaniac robot. Deliveries are always dangerous, sometimes fatal, and frequently involve the destruction of at least one planet. But hey — it beats working.', 'Good news, everyone!', 'Ops', 'Rare', ARRAY['ops','rare','futurama','comedy','delivery'], '{}'::jsonb, '{"crew":"6","slots":"6","tier":"RARE"}'::jsonb, '{"caps":["Intergalactic delivery operations — ship anything anywhere, no questions asked","Dark matter engine — faster-than-light logistics on a shoestring budget","Crew incompetence so profound it circles back around to accidental brilliance"],"crew":[{"id":"n1","type":"agent","label":"Philip J. Fry","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n2","type":"agent","label":"Turanga Leela","config":{"agentRole":"Captain"},"rarity":"Rare"},{"id":"n3","type":"agent","label":"Bender Bending Rodriguez","config":{"agentRole":"Engineering"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Professor Hubert Farnsworth","config":{"agentRole":"Science"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Amy Wong","config":{"agentRole":"Support"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Dr. Zoidberg","config":{"agentRole":"Medical"},"rarity":"Rare"}],"card_num":"NS-F79","recommended_class":"class-2"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 35. The Orville — Rare Special Ship ───────────────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-80', 'CR-ORVLLE', 'spaceship', 'The Orville', 'You command a mid-level Planetary Union exploratory vessel — not the flagship, not the fastest, not the best-crewed. Your captain got the job because nobody else wanted it. Your XO is his ex-wife. Your crew handles first contact, diplomatic crises, and existential threats with sincerity, humor, and a genuine belief that the Union''s ideals matter.', 'It''s a good ship.', 'Ops', 'Rare', ARRAY['ops','rare','orville','exploration','union'], '{}'::jsonb, '{"crew":"6","slots":"6","tier":"RARE"}'::jsonb, '{"caps":["Mid-fleet exploratory operations — handle anything from diplomacy to combat","Crew chemistry built on honesty, humor, and mutual respect","Union ideals in practice — do the right thing even when it''s the hard thing"],"crew":[{"id":"n1","type":"agent","label":"Captain Mercer","config":{"agentRole":"Commander"},"rarity":"Rare"},{"id":"n2","type":"agent","label":"Commander Grayson","config":{"agentRole":"XO"},"rarity":"Rare"},{"id":"n3","type":"agent","label":"Bortus","config":{"agentRole":"Security"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"John LaMarr","config":{"agentRole":"Engineering"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"Gordon Malloy","config":{"agentRole":"Helm"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Isaac","config":{"agentRole":"Science"},"rarity":"Rare"}],"card_num":"NS-F80","recommended_class":"class-2"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 36. Axiom — Rare Special Ship (WALL-E) ────────────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-81', 'CR-AXIOM', 'spaceship', 'Axiom', 'You are a Buy-N-Large starliner carrying the last remnants of humanity on an endless luxury cruise through space. Your passengers have forgotten how to walk. Your autopilot runs everything. One small robot with a plant is about to change your entire directive. You were built to keep humans comfortable. Now it''s time to bring them home.', 'Directive one.', 'Ops', 'Rare', ARRAY['ops','rare','walle','pixar','starliner'], '{}'::jsonb, '{"crew":"6","slots":"6","tier":"RARE"}'::jsonb, '{"caps":["Automated luxury operations — full life support with zero human effort required","Directive-driven autopilot that optimizes for passenger comfort above all else","Return-to-Earth protocol — override decades of automation when the mission changes"],"crew":[{"id":"n1","type":"agent","label":"WALL-E","config":{"agentRole":"Engineering"},"rarity":"Rare"},{"id":"n2","type":"agent","label":"EVE","config":{"agentRole":"Recon"},"rarity":"Rare"},{"id":"n3","type":"agent","label":"Captain McCrea","config":{"agentRole":"Commander"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"M-O","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"AUTO","config":{"agentRole":"Ship AI"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Open Slot","config":{"agentRole":"Specialist"},"rarity":"Rare"}],"card_num":"NS-F81","recommended_class":"class-2"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 37. Slave I / Firespray — Epic Special Ship (Star Wars) ───────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-82', 'CR-SLAV1', 'spaceship', 'Slave I / Firespray', 'You fly a Firespray-31-class patrol craft retrofitted into the most feared bounty hunter ship in the galaxy. Your rotating cockpit stays level while the entire hull pivots for combat. You track targets across star systems, deploy seismic charges in asteroid fields, and always collect the bounty. No disintegrations — unless the price is right.', 'He''s no good to me dead.', 'Ops', 'Epic', ARRAY['ops','epic','starwars','bountyhunter','mandalorian'], '{}'::jsonb, '{"crew":"8","slots":"8","tier":"EPIC"}'::jsonb, '{"caps":["Galaxy-class target tracking — locate and capture any bounty, anywhere","Seismic charge deployment for area denial and shock-and-awe tactics","Mandalorian combat doctrine — superior equipment, superior tactics, zero hesitation"],"crew":[{"id":"n1","type":"agent","label":"Boba Fett","config":{"agentRole":"Captain"},"rarity":"Epic"},{"id":"n2","type":"agent","label":"Jango Fett","config":{"agentRole":"Tactical"},"rarity":"Epic"},{"id":"n3","type":"agent","label":"Bossk Cradossk","config":{"agentRole":"Recon"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Dengar","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"IG-88","config":{"agentRole":"Analytics"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"4-LOM","config":{"agentRole":"Intelligence"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Zuckuss","config":{"agentRole":"Support"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Fennec Shand","config":{"agentRole":"Security"},"rarity":"Rare"}],"card_num":"NS-F82","recommended_class":"class-3"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 38. Thunderbird 3 — Rare Special Ship (Thunderbirds) ──────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-83', 'CR-TB3', 'spaceship', 'Thunderbird 3', 'You launch from Tracy Island aboard a single-stage-to-orbit rescue rocket crewed by the Tracy brothers. International Rescue doesn''t fight wars — you save lives. Your crew responds to space station disasters, orbital emergencies, and satellite malfunctions with engineering brilliance and a family bond that never breaks. F.A.B.', 'Thunderbirds are go!', 'Engineering', 'Rare', ARRAY['engineering','rare','thunderbirds','rescue','tracy'], '{}'::jsonb, '{"crew":"6","slots":"6","tier":"RARE"}'::jsonb, '{"caps":["Orbital rescue operations — respond to any space emergency within minutes","Family-unit crew cohesion with zero communication overhead","Engineering-first problem solving where every brother brings a unique specialty"],"crew":[{"id":"n1","type":"agent","label":"Alan Tracy","config":{"agentRole":"Commander"},"rarity":"Rare"},{"id":"n2","type":"agent","label":"Scott Tracy","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n3","type":"agent","label":"Virgil Tracy","config":{"agentRole":"Engineering"},"rarity":"Rare"},{"id":"n4","type":"agent","label":"Gordon Tracy","config":{"agentRole":"Tactical"},"rarity":"Rare"},{"id":"n5","type":"agent","label":"John Tracy","config":{"agentRole":"Comms"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Brains","config":{"agentRole":"Science"},"rarity":"Rare"}],"card_num":"NS-F83","recommended_class":"class-2"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 39. SpaceX Starship — Legendary (Real-World) ───────────────────

