VALUES ('ship-84', 'CR-SPACEX', 'spaceship', 'SpaceX Starship', 'You command the most ambitious commercial space program in history — building reusable rockets, deploying a global satellite internet constellation, and making humanity multiplanetary. Your crew isn''t astronauts. It''s an empire of companies, each pushing a different frontier. Move fast. Launch often. Land everything.', 'Occupy Mars.', 'Engineering', 'Legendary', ARRAY['engineering','legendary','spacex','realworld','musk'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"LEGENDARY"}'::jsonb, '{"caps":["Reusable launch architecture — iterate faster than any competitor can design","Multi-company synergy where automotive, AI, and aerospace reinforce each other","Starlink-scale infrastructure that generates revenue while funding the Mars mission"],"crew":[{"id":"n1","type":"agent","label":"Elon Musk","config":{"agentRole":"CEO"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Starlink","config":{"agentRole":"Comms"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Tesla","config":{"agentRole":"Manufacturing"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"xAI / Grok","config":{"agentRole":"Intelligence"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"X (Twitter)","config":{"agentRole":"Marketing"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"Neuralink","config":{"agentRole":"Research"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"The Boring Company","config":{"agentRole":"Infrastructure"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Musk Foundation","config":{"agentRole":"Governance"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"SpaceX Raptor","config":{"agentRole":"Engineering"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Optimus (Tesla Bot)","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Starbase","config":{"agentRole":"Logistics"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Open Slot","con