VALUES ('ship-85', 'CR-META', 'spaceship', 'Meta Platforms', 'You connect three billion humans across a family of apps — routing social graphs, messaging, commerce, and AI through the largest communication infrastructure ever built. Your bet on mixed reality is reshaping how people work and play. Your open-source AI models power half the world''s startups. The metaverse is the mission. The data is the fuel.', 'Move fast with stable infra.', 'Content', 'Legendary', ARRAY['content','legendary','meta','realworld','zuckerberg'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"LEGENDARY"}'::jsonb, '{"caps":["Three-billion-user social graph powering every product decision","Open-source AI (Llama) that builds ecosystem while competing at the frontier","Mixed reality platform bridging physical and digital interaction"],"crew":[{"id":"n1","type":"agent","label":"Mark Zuckerberg","config":{"agentRole":"CEO"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Meta AI / Llama","config":{"agentRole":"Intelligence"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Facebook","config":{"agentRole":"Marketing"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Instagram","config":{"agentRole":"Content"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"WhatsApp","config":{"agentRole":"Comms"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"Reality Labs","config":{"agentRole":"Engineering"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Threads","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Messenger","config":{"agentRole":"Support"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"Workplace","config":{"agentRole":"Collaboration"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Ray-Ban Meta","config":{"agentRole":"Research"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Connectivity","config":{"agentRole":"Infrastructure"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Open Slot","config":{"agen